import React, { useState, useEffect } from 'react';
import VideoPlayer from './VideoPlayer';
import RateCard from './RateCard';
import { currencyService } from '../../services/currencyService';
import { videoService } from '../../services/videoService';
import './TVDashboard.css';

const TVDashboard = () => {
    const [currencies, setCurrencies] = useState([]);
    const [activeVideo, setActiveVideo] = useState(null);
    const [currentDateTime, setCurrentDateTime] = useState(new Date());
    const [loading, setLoading] = useState(true);
    const [lastUpdate, setLastUpdate] = useState('');

    useEffect(() => {
        loadData();
        const interval = setInterval(loadData, 30000);
        const timeInterval = setInterval(() => setCurrentDateTime(new Date()), 1000);
        return () => {
            clearInterval(interval);
            clearInterval(timeInterval);
        };
    }, []);

    const loadData = async () => {
        try {
            const [ratesRes, videoRes] = await Promise.all([
                currencyService.getAll(),
                videoService.getActiveVideo()
            ]);
            
            if (ratesRes.success) {
                setCurrencies(ratesRes.data);
                if (ratesRes.data.length > 0 && ratesRes.data[0].updated_at) {
                    setLastUpdate(new Date(ratesRes.data[0].updated_at).toLocaleString());
                }
            }
            
            if (videoRes.success) {
                setActiveVideo(videoRes.data);
            }
        } catch (error) {
            console.error('Error loading TV data:', error);
        } finally {
            setLoading(false);
        }
    };

    const formatDateTime = (date) => ({
        date: date.toLocaleDateString('en-GB', { day: '2-digit', month: '2-digit', year: 'numeric' }),
        time: date.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true })
    });

    const { date, time } = formatDateTime(currentDateTime);

    if (loading) {
        return (
            <div className="tv-loading">
                <div className="spinner"></div>
                <p>Loading Dashboard...</p>
            </div>
        );
    }

    return (
        <div className="tv-dashboard">
            <div className="tv-header">
                <div className="tv-logo">
                    <i className="fas fa-landmark"></i>
                    <h1>DASHEN BANK</h1>
                    <span className="tv-tagline">Exchange Rate Board</span>
                </div>
                <div className="tv-datetime">
                    <div className="tv-date">{date}</div>
                    <div className="tv-time">{time}</div>
                </div>
            </div>

            <div className="tv-main">
                <div className="tv-video-section">
                    <VideoPlayer video={activeVideo} />
                    <div className="video-caption">
                        <i className="fas fa-play-circle"></i>
                        <span>Promotional Video</span>
                    </div>
                </div>

                <div className="tv-rates-section">
                    <div className="rates-header">
                        <h2><i className="fas fa-exchange-alt"></i> Live Exchange Rates</h2>
                        <div className="last-update">
                            <i className="fas fa-clock"></i> Updated: {lastUpdate || 'Today'}
                        </div>
                    </div>
                    
                    <div className="rates-scroll">
                        {currencies.map((currency, index) => (
                            <RateCard key={currency.id} currency={currency} index={index} />
                        ))}
                    </div>
                </div>
            </div>

            <div className="tv-footer">
                <div className="ticker">
                    <div className="ticker-content">
                        <span>🏦 Dashen Bank - Authorized by National Bank of Ethiopia</span>
                        <span>📞 Contact Center: 8076</span>
                        <span>💱 Competitive Exchange Rates</span>
                        <span>🔒 Safe & Secure Transactions</span>
                        <span>🌟 24/7 Customer Support</span>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default TVDashboard;
